// Naive UUPS+1967 proxy doesn't work for EIP7702 — EOA delegations need a relay
// that distinguishes self-calls (admin / etherscan) from EOA-side delegatecalls.
contract NaiveProxy {
    address public implementation;
    fallback() external payable {
        (bool ok, bytes memory r) = implementation.delegatecall(msg.data);
        if (!ok) assembly { revert(add(r, 32), mload(r)) }
        assembly { return(add(r, 32), mload(r)) }
    }
}

