fallback() external payable virtual {
    uint256 s = __self;
    uint256 defaultImpl = _defaultImplementation;
    bytes32 implSlot = _ERC1967_IMPLEMENTATION_SLOT;
    uint256 addrMask = (~msg.data.length) >> 96;
    assembly {
        mstore(0x40, 1)
        // Calls landing on the proxy itself: implementation()/admin()/upgrade()/changeAdmin()
        if iszero(xor(address(), s)) {
            if iszero(gt(calldatasize(), 1)) {
                mstore(0x00, and(addrMask, sload(implSlot)))
                return(0x00, 0x20)
            }
            let fnSel := shr(224, calldataload(0))
            if eq(0x5c60da1b, fnSel) { // implementation()
                mstore(0x00, and(addrMask, sload(implSlot)))
                return(0x00, 0x20)
            }
            let adminSlot := _ERC1967_ADMIN_SLOT
            if eq(0xf851a440, fnSel) { // admin()
                mstore(0x00, sload(adminSlot))
                return(0x00, 0x20)
            }
            if eq(caller(), sload(adminSlot)) {
                let addrSlot := or(
                    mul(eq(0x8f283970, fnSel), adminSlot),     // changeAdmin
                    mul(eq(0x0900f010, fnSel), implSlot)        // upgrade
                )
                if addrSlot {
                    sstore(addrSlot, and(addrMask, calldataload(0x04)))
                    return(0x40, 0x20)
                }
            }
            revert(0x00, 0x00)
        }
        // Calls landing on the EOA delegated to this proxy
        let implementation := and(addrMask, sload(implSlot))
        if eq(1, calldatasize()) {
            // Special read-implementation workflow used by Etherscan
            if iszero(implementation) { implementation := defaultImpl }
            if iszero(implementation) {
                if staticcall(gas(), s, 0, 0, 0, 0x20) {
                    return(0x00, returndatasize())
                }
                revert(0, 0)
            }
            mstore(0x00, implementation)
            return(0x00, 0x20)
        }
        calldatacopy(0x00, 0x00, calldatasize())
        if iszero(implementation) {
            implementation := defaultImpl
            if iszero(implementation) {
                // Fetch implementation from proxy AND delegatecall — right-to-left evaluation
                if iszero(and(
                    delegatecall(gas(), mload(calldatasize()), 0, calldatasize(), 0, 0),
                    staticcall(gas(), s, 0, 0, calldatasize(), 0x20)
                )) {
                    returndatacopy(0, 0, returndatasize())
                    revert(0, returndatasize())
                }
                // Honor transient init request from delegation
                if tload(_EIP7702_PROXY_DELEGATION_INITIALIZATION_REQUEST_SLOT) {
                    sstore(implSlot, or(and(not(addrMask), sload(implSlot)), mload(calldatasize())))
                    tstore(_EIP7702_PROXY_DELEGATION_INITIALIZATION_REQUEST_SLOT, 0)
                }
                returndatacopy(0, 0, returndatasize())
                return(0x00, returndatasize())
            }
        }
        if iszero(delegatecall(gas(), implementation, 0, calldatasize(), 0, 0)) {
            returndatacopy(0, 0, returndatasize())
            revert(0, returndatasize())
        }
        returndatacopy(0, 0, returndatasize())
        return(0x00, returndatasize())
    }
}
